/**
 * @param {string} s
 * @return {number}
 */
var removePalindromeSub = function(s) {
    // If the string is already a palindrome, we can remove it in one step
    const isPalindrome = (str) => {
        let left = 0, right = str.length - 1;
        while (left < right) {
            if (str[left] !== str[right]) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }
    
    if (isPalindrome(s)) {
        return 1;
    }
    return 2; // If not a palindrome, it can be removed in two steps (remove all 'a's and then all 'b's, or vice versa)
    
};
